or_create_related('report_layouts',\n            { layout_id => $layout });\n    }\n\n    my $search = {};\n\n    $search->{layout_id} = { '!=' => [ -and => @$layouts ] }\n        if @$layouts;\n    $self->search_related('report_layouts', $search)->delete;\n\n    my $groups = $args->{groups};\n\n    foreach my $group (@$groups)\n    {\n        $self->find_or_create_related('report_groups',\n            { group_id => $group });\n    }\n\n    my $search_groups = {};\n\n    $search_groups->{group_id} = { '!=' => [ -and => @$groups ] }\n        if @$groups;\n    $self->search_related('report_groups', $search_groups)->delete;\n\n    $guard->commit;\n\n    return $self;\n}\n\n=head2 Remove\nFunction to delete a report - it requires the schema to be passed in and will return nothing.\nIf the ID is invalid, or there's nothing to delete, it will do nothing.\n\nsub remove\n{   my $self = shift;\n\n    return if !$self->in_storage || $self->deleted;\n\n    my $guard = $self->result_source->schema->txn_scope_guard;\n\n    $self->update({ deleted => DateTime->now });\n\n    $guard->commit;\n}\n\n=head2 Create PDF\nFunction to create a PDF of the report - it will return a PDF object","label":"create_pdf($self,$record,$user)","parameters":[{"label":"$self"},{"label":"$record"},{"label":"$user"}]},"containerName":"main::","detail":"($self,$record,$user)","range":{"start":{"line":289,"character":0},"end":{"character":9999,"line":331}},"definition":"sub","children":[{"line":290,"localvar":"my","kind":13,"definition":"my","containerName":"create_pdf","name":"$self"},{"line":290,"kind":13,"containerName":"create_pdf","name":"$record"},{"line":290,"containerName":"create_pdf","name":"$user","kind":13},{"name":"$marking","containerName":"create_pdf","definition":"my","kind":13,"localvar":"my","line":292},{"line":292,"containerName":"create_pdf","name":"$self","kind":13},{"name":"_read_security_marking","containerName":"create_pdf","kind":12,"line":292},{"kind":13,"definition":"my","conta